const importFilePath = '/files/job-tracker/jobs-import-example.json';
const importFileName = $json.fileName || 'jobs-import-example.json';
const importFormat = String($json.fileExtension || importFileName.split('.').pop() || 'json').toLowerCase();
const text = String($json.fileText || '');

function parseCsvRows(input) {
  const rows = [];
  let row = [];
  let field = '';
  let quoted = false;
  for (let i = 0; i < input.length; i++) {
    const char = input[i];
    if (quoted) {
      if (char === '"' && input[i + 1] === '"') { field += '"'; i++; }
      else if (char === '"') quoted = false;
      else field += char;
    } else if (char === '"') quoted = true;
    else if (char === ',') { row.push(field); field = ''; }
    else if (char === '\n') { row.push(field); rows.push(row); row = []; field = ''; }
    else if (char !== '\r') field += char;
  }
  if (field.length || row.length) { row.push(field); rows.push(row); }
  return rows.filter(values => values.some(value => String(value).trim() !== ''));
}

function csvToObjects(input) {
  const rows = parseCsvRows(input);
  if (rows.length < 2) return [];
  const headers = rows[0].map(header => String(header).trim());
  return rows.slice(1).map(row => Object.fromEntries(headers.map((header, index) => [header, row[index] ?? ''])));
}

let records;
if (importFormat === 'csv') records = csvToObjects(text);
else if (importFormat === 'json') {
  const parsed = JSON.parse(text || '[]');
  records = Array.isArray(parsed) ? parsed : Array.isArray(parsed.jobs) ? parsed.jobs : [parsed];
} else {
  throw new Error(`Unsupported import format: ${importFormat}`);
}

return [{ json: { importSource: 'local-file-import-v2', importFilePath, importFileName, importFormat, rawRecords: records, recordsSeen: records.length } }];

const requiredFields = ['jobTitle', 'company', 'description'];
const listFields = ['requiredSkills', 'preferredSkills', 'languageRequirements'];

function normalizeList(value) {
  if (Array.isArray(value)) return value.map(item => String(item).trim()).filter(Boolean);
  if (value === undefined || value === null || value === '') return [];
  const text = String(value).trim();
  if (!text) return [];
  if (text.startsWith('[')) {
    try {
      const parsed = JSON.parse(text);
      if (Array.isArray(parsed)) return parsed.map(item => String(item).trim()).filter(Boolean);
    } catch (error) {}
  }
  return text.split(/[|;]/).map(item => item.trim()).filter(Boolean);
}

const validRecords = [];
const rejectedRecords = [];
for (const [index, raw] of ($json.rawRecords || []).entries()) {
  const record = { ...raw, importRowNumber: index + 1 };
  for (const field of listFields) record[field] = normalizeList(record[field]);
  const errors = [];
  for (const field of requiredFields) {
    if (!String(record[field] || '').trim()) errors.push(`Missing ${field}`);
  }
  if (record.jobUrl && !/^https?:\/\//i.test(String(record.jobUrl))) errors.push('jobUrl must start with http:// or https:// when provided');
  if (errors.length) rejectedRecords.push({ rejection_reason: errors.join('; '), raw_record: record });
  else validRecords.push(record);
}

return [{ json: { ...$json, validRecords, rejectedRecords, recordsValid: validRecords.length, recordsRejected: rejectedRecords.length } }];

const validRecords = ($json.validRecords || []).map(job => {
  const normalized = { ...job };
  normalized.location = normalized.location || 'Unknown';
  normalized.workModel = normalized.workModel || 'Unknown';
  normalized.salaryRange = normalized.salaryRange || '';
  normalized.source = normalized.source || `Local ${String($json.importFormat || '').toUpperCase()} Import`;
  normalized.applicationStatus = normalized.applicationStatus || 'Imported';
  normalized.normalizedLocation = String(normalized.workModel).toLowerCase().includes('remote') ? 'Remote' : normalized.location;
  return normalized;
});
return [{ json: { ...$json, validRecords } }];

const validRecords = ($json.validRecords || []).map(job => {
  let score = 50;
  const reasons = [];
  const risks = [];
  const workModel = String(job.workModel || '').toLowerCase();
  const description = String(job.description || '').toLowerCase();
  const salaryRange = String(job.salaryRange || '').toLowerCase();
  if (workModel.includes('remote')) { score += 20; reasons.push('+Remote work'); }
  else if (workModel.includes('hybrid')) { score += 5; reasons.push('+Hybrid work'); }
  else if (workModel.includes('on-site') || workModel.includes('onsite')) { score -= 20; risks.push('-On-site required'); }
  const reqStr = `${(job.requiredSkills || []).join(' ')} ${description}`.toLowerCase();
  if (reqStr.includes('n8n') || reqStr.includes('automation')) { score += 15; reasons.push('+Automation match'); }
  if (reqStr.includes('python') || reqStr.includes('node') || reqStr.includes('react')) { score += 10; reasons.push('+Tech stack match'); }
  if ((job.languageRequirements || []).some(lang => String(lang).toLowerCase().includes('greek'))) { score += 15; reasons.push('+Native Greek advantage'); }
  if (salaryRange.includes('€800') || salaryRange.includes('€850') || salaryRange.includes('€900') || salaryRange.includes('950')) { score -= 15; risks.push('-Low compensation'); }
  else if (!salaryRange || salaryRange.includes('competitive') || salaryRange.includes('vague')) { score -= 5; risks.push('-Vague compensation'); }
  else { score += 10; reasons.push('+Clear compensation'); }
  if (description.includes('unpaid trial')) { score -= 30; risks.push('CRITICAL RISK: Unpaid trial'); }
  if ((job.languageRequirements || []).some(lang => String(lang).toLowerCase().includes('german'))) { score -= 20; risks.push('-Requires German'); }
  return { ...job, matchScore: Math.max(0, Math.min(100, score)), reasons, risks };
});
return [{ json: { ...$json, validRecords } }];

const validRecords = ($json.validRecords || []).map(job => {
  let priority;
  if (job.matchScore >= 85) priority = 'HIGH';
  else if (job.matchScore >= 70) priority = 'MEDIUM';
  else if (job.matchScore >= 50) priority = 'LOW';
  else priority = 'SKIP';
  return { ...job, priority };
});
return [{ json: { ...$json, validRecords } }];

const validRecords = ($json.validRecords || []).map(job => {
  const risks = job.risks || [];
  let recommendedAction;
  let nextStep;
  if (job.priority === 'SKIP') { recommendedAction = 'Skip entirely'; nextStep = 'Archive without applying'; }
  else if (risks.some(r => String(r).includes('CRITICAL RISK'))) { recommendedAction = 'Skip - Critical Red Flag'; nextStep = 'Do not spend more time unless terms change'; }
  else if (risks.some(r => String(r).includes('Vague'))) { recommendedAction = 'Ask compensation and contract terms first'; nextStep = 'Send a short clarification message before tailoring materials'; }
  else if (job.priority === 'HIGH' && String(job.workModel).toLowerCase().includes('remote')) { recommendedAction = 'Apply now with tailored CV'; nextStep = 'Tailor CV and submit today'; }
  else if (job.priority === 'HIGH' || job.priority === 'MEDIUM') { recommendedAction = 'Build mini proof-of-work before applying'; nextStep = 'Create a small automation demo aligned to the role'; }
  else { recommendedAction = 'Save for later'; nextStep = 'Review only after higher-priority roles are handled'; }
  const tailoredAngle = job.priority === 'HIGH' ? 'Lead with local-first n8n, Docker, PostgreSQL, and automation evidence.' : 'Mention relevant automation experience only if the role clears compensation and logistics checks.';
  return { ...job, recommendedAction, nextStep, tailoredAngle };
});
return [{ json: { ...$json, validRecords } }];

const seen = new Map();
let duplicateCandidates = 0;
const validRecords = ($json.validRecords || []).map(job => {
  const key = `${String(job.company || '').toLowerCase()}::${String(job.jobTitle || '').toLowerCase()}`;
  const count = seen.get(key) || 0;
  seen.set(key, count + 1);
  if (count > 0) duplicateCandidates++;
  return {
    job_title: job.jobTitle,
    company: job.company,
    work_model: job.workModel,
    normalized_location: job.normalizedLocation,
    salary_range: job.salaryRange,
    source: job.source,
    job_url: job.jobUrl || '',
    application_status: job.applicationStatus,
    match_score: job.matchScore,
    priority: job.priority,
    reasons: job.reasons || [],
    risks: job.risks || [],
    recommended_action: job.recommendedAction,
    next_step: job.nextStep,
    tailored_angle: job.tailoredAngle,
    required_skills: job.requiredSkills || [],
    preferred_skills: job.preferredSkills || [],
    language_requirements: job.languageRequirements || [],
    notes: job.notes,
    raw_job: job
  };
});
return [{ json: { ...$json, validRecords, duplicateCandidates } }];

