WITH src AS (
  SELECT * FROM jsonb_to_recordset($2::jsonb) AS x(
    rejection_reason text,
    raw_record jsonb
  )
), inserted AS (
  INSERT INTO public.job_import_rejections (import_run_id, rejection_reason, raw_record)
  SELECT $1::bigint, rejection_reason, raw_record
  FROM src
  RETURNING id
)
SELECT $1::bigint AS import_run_id, count(*)::integer AS rejected_rows
FROM inserted;
